using Store;

namespace ShoppingCart.Tests;

[TestClass]
public class ShoppingCartTests
{
    private Store.ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup()
    {
        _cart = new Store.ShoppingCart();
    }

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 9.99m);

        Assert.AreEqual(9.99m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_TotalSumsAll()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 2, price: 5.00m);

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_CombinesQuantities()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-001", quantity: 3, price: 10.00m);

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_QuantityGreaterThanOne_MultipliesPrice()
    {
        _cart.AddItem("SKU-001", quantity: 5, price: 3.00m);

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void AddItem_ZeroQuantity_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: 0, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativeQuantity_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: -1, price: 10.00m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _cart.AddItem("SKU-001", quantity: 1, price: -5.00m));
    }

    [TestMethod]
    public void AddItem_NullSku_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _cart.AddItem(null!, quantity: 1, price: 10.00m));
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_NoLongerInTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 10.00m);
        _cart.AddItem("SKU-002", quantity: 1, price: 5.00m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(5.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_OnlyItem_TotalIsZero()
    {
        _cart.AddItem("SKU-001", quantity: 2, price: 7.50m);

        _cart.RemoveItem("SKU-001");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_Throws()
    {
        Assert.ThrowsExactly<InvalidOperationException>(
            () => _cart.RemoveItem("SKU-MISSING"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _cart.RemoveItem(null!));
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterAddAndRemove_ReflectsRemainingItems()
    {
        _cart.AddItem("A", quantity: 1, price: 100.00m);
        _cart.AddItem("B", quantity: 3, price: 20.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(60.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_FractionalPrices_CalculatesCorrectly()
    {
        _cart.AddItem("SKU-001", quantity: 3, price: 1.33m);

        Assert.AreEqual(3.99m, _cart.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    public void ApplyCoupon_ValidCode_ReducesTotal()
    {
        _cart.AddItem("SKU-001", quantity: 1, price: 100.00m);

        _cart.ApplyCoupon("SAVE10");

        Assert.IsTrue(_cart.CalculateTotal() < 100.00m,
            "Total should be less than original price after a valid coupon.");
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _cart.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_EmptyCode_Throws()
    {
        Assert.ThrowsExactly<ArgumentException>(
            () => _cart.ApplyCoupon(string.Empty));
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }
}

